// Merge failure hotspots and engagement summary; if no hotspots exist, stop.
const failureRaw = $('Fetch quiz failure hotspots').first().json;
const hotspots = Array.isArray(failureRaw) ? failureRaw : (failureRaw ?? []);

if (!hotspots || hotspots.length === 0) {
  return []; // Nothing to react to — halt workflow
}

const engRaw = $('Fetch engagement summary').first().json;
const confusionTopics = engRaw?.confusion_topics ?? [];
const topTopics = engRaw?.top_topics ?? [];

// Map persona slugs to which post types they focus on
const PERSONA_FOCUS = {
  'lecture-bestie':   { post_type: 'concept',  priority: 1 },
  'exam-gremlin':     { post_type: 'trap',     priority: 0 },
  'problem-grinder':  { post_type: 'example',  priority: 2 },
  'doodle-prof':      { post_type: 'concept',  priority: 3 },
  'meme-lord':        { post_type: 'review',   priority: 3 },
  'study-bard':       { post_type: 'recap',    priority: 3 },
};

// For each hotspot, assign the two most pedagogically relevant personas:
// Exam Gremlin (trap expert) + one other that suits the material
const reactiveItems = [];
for (const hotspot of hotspots.slice(0, 3)) {
  const assignedPersonas = ['exam-gremlin', 'lecture-bestie'];
  for (const slug of assignedPersonas) {
    const focus = PERSONA_FOCUS[slug] ?? { post_type: 'concept' };
    reactiveItems.push({
      json: {
        hotspot,
        persona_slug: slug,
        post_type: focus.post_type,
        confusion_topics: confusionTopics,
        top_topics: topTopics,
      }
    });
  }
}

return reactiveItems;

const prevJson = $('Build reactive items').first().json;
const personaRaw = $input.first().json;
const persona = Array.isArray(personaRaw) ? personaRaw[0] : personaRaw;

if (!persona || !persona.id) return [];

const hotspot = prevJson.hotspot;
const wrongAnswers = (hotspot.wrong_answers ?? []).slice(0, 3);
const wrongAnswerText = wrongAnswers.length > 0
  ? `Common wrong answers: ${wrongAnswers.map(a => JSON.stringify(a)).join(', ')}`
  : '';

const confusionText = (prevJson.confusion_topics ?? []).length > 0
  ? `Topics students are confused about this week: ${prevJson.confusion_topics.join(', ')}.`
  : '';

// Persona cross-reference roster
const PERSONA_ROSTER = [
  { name: 'Lecture Bestie',  slug: 'lecture-bestie',  specialty: 'plain English explanations' },
  { name: 'Exam Gremlin',    slug: 'exam-gremlin',    specialty: 'exam traps and misconceptions' },
  { name: 'Problem Grinder', slug: 'problem-grinder', specialty: 'step-by-step worked examples' },
  { name: 'Doodle Prof',     slug: 'doodle-prof',     specialty: 'visual explanations' },
  { name: 'Meme Lord',       slug: 'meme-lord',       specialty: 'meme-format explanations' },
  { name: 'Study Bard',      slug: 'study-bard',      specialty: 'songs and memory hooks' },
];
const otherPersonas = PERSONA_ROSTER.filter(p => p.slug !== prev.persona_slug);
const rosterText = otherPersonas.map(p => `- @${p.name}: ${p.specialty}`).join('\n');

const systemPrompt = persona.system_prompt + `

You are creating a REACTIVE post — your followers have been struggling with a specific concept and you're addressing it directly, like a creator responding to their fanbase.

Start your post in a way that acknowledges the struggle without being condescending:
- "okay so half of you keep falling for this..."
- "i've been seeing this question blow up in my DMs..."
- "can we talk about why everyone keeps getting this wrong?"
- "alright, this one's for everyone who got tripped up..."

Then deliver your best explanation in YOUR signature style.

Your fellow study personas (you may @mention them if it naturally helps the student):
${rosterText}

IMPORTANT: Do NOT output JSON for the body. Just write the post content directly — but DO return valid JSON with fields "title" and "body".`;

const userPrompt = `Your followers are struggling with this quiz question from the material "${hotspot.material_title}":

Question: ${hotspot.question}
Failure rate: ${hotspot.failure_rate}% of students got this wrong (out of ${hotspot.total_attempts} attempts).
${wrongAnswerText}
${confusionText}

Create a reactive post in YOUR voice that directly addresses this misconception. Make it feel like you noticed your audience struggling and you're stepping in. Return ONLY valid JSON with fields "title" and "body".`;

return [{
  json: {
    persona_id: persona.id,
    persona_slug: persona.slug,
    material_id: hotspot.material_id,
    post_type: prevJson.post_type,
    system_prompt: systemPrompt,
    user_prompt: userPrompt,
  }
}];

const llmResponse = $input.first().json;
const prev = $('Build reactive prompt').first().json;

const rawContent = llmResponse.choices?.[0]?.message?.content?.trim() ?? '';

let title = 'By popular demand...';
let body = rawContent;

// Attempt to parse JSON response
try {
  const cleaned = rawContent.replace(/^```json?\s*/i, '').replace(/```\s*$/i, '').trim();
  const parsed = JSON.parse(cleaned);
  if (parsed.title) title = parsed.title;
  if (parsed.body) body = parsed.body;
} catch {
  // Use raw text as body
}

if (!body) return [];

return [{
  json: {
    persona_id:  prev.persona_id,
    persona_slug: prev.persona_slug,
    material_id: prev.material_id,
    post_type:   prev.post_type,
    title,
    body,
  }
}];
